module updown_counter_3bit (
    input clk,
    input rst_n,
    input ctrl,
    output reg [2:0] count
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        count <= 3'b000;
    else if (ctrl)
        count <= count + 1;
    else
        count <= count - 1;
end

endmodule
